
const fs = require('fs');
const path = require('path');

const root = process.cwd();
const backupDir = path.join(root, '.customer-header-auto-backup');

const filePayloads = {
  "services/customerHeaderService.ts": "",
  "app/customer-header-settings.tsx": "",
  "utils/logoHelper.ts": "",
  "supabase/migrations/20260429013000_add_customer_receipt_headers.sql": ""
};

function ensureDir(dir) {
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
}

function decodeBase64(value) {
  return Buffer.from(value, 'base64').toString('utf8');
}

function backup(targetPath) {
  if (!fs.existsSync(targetPath)) return null;
  ensureDir(backupDir);
  const backupPath = path.join(
    backupDir,
    `${path.relative(root, targetPath).replace(/[\\/]/g, '__')}.${Date.now()}.bak`
  );
  fs.copyFileSync(targetPath, backupPath);
  return backupPath;
}

function writeFile(targetPath, content) {
  ensureDir(path.dirname(targetPath));
  fs.writeFileSync(targetPath, content, 'utf8');
}

function readFile(relativePath) {
  const targetPath = path.join(root, relativePath);
  if (!fs.existsSync(targetPath)) {
    throw new Error(`Missing file: ${relativePath}`);
  }
  return fs.readFileSync(targetPath, 'utf8');
}

function writeBack(relativePath, content) {
  const targetPath = path.join(root, relativePath);
  backup(targetPath);
  fs.writeFileSync(targetPath, content, 'utf8');
  console.log('Updated:', relativePath);
}

function replaceOrThrow(source, searchValue, replaceValue, label) {
  if (!source.includes(searchValue)) {
    throw new Error(`Could not find pattern for: ${label}`);
  }
  return source.replace(searchValue, replaceValue);
}

function patchDatabaseTypes() {
  const relativePath = 'types/database.ts';
  let content = readFile(relativePath);

  if (content.includes('receipt_header_mode?:')) {
    console.log('Skipped types/database.ts (already patched)');
    return;
  }

  const insertBlock = `
  receipt_header_mode?: 'default' | 'full_banner' | 'generated';
  receipt_header_banner_url?: string | null;
  receipt_header_logo_url?: string | null;
  receipt_header_left_title?: string | null;
  receipt_header_left_subtitle?: string | null;
  receipt_header_right_title?: string | null;
  receipt_header_right_subtitle?: string | null;
  receipt_header_primary_color?: string | null;
  receipt_header_secondary_color?: string | null;
  receipt_header_text_color?: string | null;
`;

  const regex = /export\s+interface\s+Customer\s*\{/;
  const match = content.match(regex);
  if (!match) {
    throw new Error('Could not find Customer interface in types/database.ts');
  }

  content = content.replace(regex, (m) => `${m}\n${insertBlock}`);
  writeBack(relativePath, content);
}

function patchReceiptPreview() {
  const relativePath = 'app/receipt-preview.tsx';
  let content = readFile(relativePath);

  if (content.includes("import { getCustomerReceiptHeaderBase64 } from '@/utils/logoHelper';")) {
    console.log('Skipped import patch in app/receipt-preview.tsx');
  } else {
    content = replaceOrThrow(
      content,
      "import { getReceiptLogoBase64 } from '@/utils/logoHelper';",
      "import { getCustomerReceiptHeaderBase64 } from '@/utils/logoHelper';",
      'receipt-preview import'
    );
  }

  if (content.includes('const mergedCustomer = {')) {
    console.log('Skipped merged customer patch in app/receipt-preview.tsx');
  } else {
    content = replaceOrThrow(
      content,
      `const scopedMovementData = {
        ...movementData,
        customers: movementData.customers || accessibleCustomer,
      };`,
      `const mergedCustomer = {
        ...accessibleCustomer,
        ...(movementData.customers || {}),
      };

      const scopedMovementData = {
        ...movementData,
        customers: mergedCustomer,
      };`,
      'receipt-preview merged customer block'
    );
  }

  if (content.includes('getCustomerReceiptHeaderBase64(customerData, forceRefresh)')) {
    console.log('Skipped logo call patch in app/receipt-preview.tsx');
  } else {
    content = replaceOrThrow(
      content,
      'logoDataUrl = await getReceiptLogoBase64(forceRefresh);',
      'logoDataUrl = await getCustomerReceiptHeaderBase64(customerData, forceRefresh);',
      'receipt-preview logo call'
    );
  }

  writeBack(relativePath, content);
}

function patchCustomerDetails() {
  const relativePath = 'app/customer-details.tsx';
  let content = readFile(relativePath);

  if (!content.includes("getCustomerReceiptHeaderBase64")) {
    content = replaceOrThrow(
      content,
      "import { getLogoBase64 } from '@/utils/logoHelper';",
      "import { getCustomerReceiptHeaderBase64 } from '@/utils/logoHelper';",
      'customer-details import'
    );
  }

  if (!content.includes('const handleCustomerHeaderSettings = () => {')) {
    const injection = `
  const handleCustomerHeaderSettings = () => {
    if (!customer) {
      return;
    }

    router.push({
      pathname: '/customer-header-settings',
      params: {
        customerId: customer.id,
        customerName: customer.name,
        accountNumber: customer.account_number,
      },
    });
  };

  const handlePrint = () => {`;

    content = replaceOrThrow(
      content,
      'const handlePrint = () => {',
      injection,
      'customer-details handler injection'
    );
  }

  if (!content.includes('logoDataUrl = await getCustomerReceiptHeaderBase64(customer);')) {
    content = replaceOrThrow(
      content,
      'logoDataUrl = await getLogoBase64();',
      'logoDataUrl = await getCustomerReceiptHeaderBase64(customer);',
      'customer-details logo call'
    );
  }

  let buttonInserted = false;
  const buttonBlock = `
          <TouchableOpacity
            onPress={handleCustomerHeaderSettings}
            style={{
              backgroundColor: '#ECFDF5',
              borderWidth: 1,
              borderColor: '#A7F3D0',
              paddingVertical: 10,
              paddingHorizontal: 14,
              borderRadius: 12,
              alignItems: 'center',
              justifyContent: 'center',
              marginTop: 10,
            }}
          >
            <Text style={{ color: '#065F46', fontWeight: '700' }}>ترويسة السند</Text>
          </TouchableOpacity>
`;

  const candidates = [
    {
      find: "</TouchableOpacity>\n        <TouchableOpacity\n          onPress={handlePrint}",
      replace: `</TouchableOpacity>${buttonBlock}        <TouchableOpacity\n          onPress={handlePrint}`,
    },
    {
      find: "</TouchableOpacity>\n          <TouchableOpacity\n            onPress={handlePrint}",
      replace: `</TouchableOpacity>${buttonBlock}          <TouchableOpacity\n            onPress={handlePrint}`,
    },
    {
      find: "</TouchableOpacity>\n        <TouchableOpacity onPress={handlePrint}",
      replace: `</TouchableOpacity>${buttonBlock}        <TouchableOpacity onPress={handlePrint}`,
    },
  ];

  if (!content.includes('ترويسة السند')) {
    for (const candidate of candidates) {
      if (content.includes(candidate.find)) {
        content = content.replace(candidate.find, candidate.replace);
        buttonInserted = true;
        break;
      }
    }
  } else {
    buttonInserted = true;
  }

  writeBack(relativePath, content);

  if (!buttonInserted) {
    console.warn('');
    console.warn('WARNING: route handler was added, but the visible button was not injected automatically.');
    console.warn('Open app/customer-details.tsx and add a button with onPress={handleCustomerHeaderSettings} manually if needed.');
    console.warn('');
  }
}

function writePayloadFiles() {
  for (const [relativePath, encoded] of Object.entries(filePayloads)) {
    const targetPath = path.join(root, relativePath);
    backup(targetPath);
    writeFile(targetPath, decodeBase64(encoded));
    console.log('Written:', relativePath);
  }
}

function main() {
  try {
    ensureDir(backupDir);

    writePayloadFiles();
    patchDatabaseTypes();
    patchReceiptPreview();
    patchCustomerDetails();

    console.log('');
    console.log('Done successfully.');
    console.log('Next steps:');
    console.log('1) Make sure assets/images/default-header.png exists');
    console.log('2) Run your Supabase migration / db push');
    console.log('3) Run: npm run typecheck');
    console.log('4) Run: npx expo start -c');
  } catch (error) {
    console.error('');
    console.error('Patch failed:', error.message);
    process.exit(1);
  }
}

main();
